const formatearFecha = (fecha) => new Intl.DateTimeFormat('es-AR', { day: '2-digit', month: '2-digit', year: 'numeric' }).format(new Date(fecha));
const parseNumeroBasico = (valor) => {
  if (typeof valor === 'number') return Number.isFinite(valor) ? valor : 0;
  let texto = (valor ?? '').toString().trim().replace(/\s/g, '').replace(/[^\d,.-]/g, '');
  if (!texto || texto === '-' || texto === ',' || texto === '.') return 0;
  const ultimoPunto = texto.lastIndexOf('.');
  const ultimaComa = texto.lastIndexOf(',');
  if (ultimoPunto >= 0 && ultimaComa >= 0) {
    texto = ultimaComa > ultimoPunto
      ? texto.replace(/\./g, '').replace(',', '.')
      : texto.replace(/,/g, '');
  } else if (ultimaComa >= 0) {
    texto = texto.replace(/\./g, '').replace(',', '.');
  } else {
    const partes = texto.split('.');
    if (partes.length > 2) {
      const decimal = partes.pop();
      texto = `${partes.join('')}.${decimal}`;
    }
  }
  return parseFloat(texto) || 0;
};
const parseNumeroConSigno = (valor) => {
  let texto = (valor ?? '').toString().trim().replace(/[^\d,.-]/g, '');
  texto = texto.includes(',') ? texto.replace(/\./g, '').replace(',', '.') : texto.replace(/,/g, '');
  return parseFloat(texto) || 0;
};
const clonarEstructuraSimple = (valor) => {
  try {
    return typeof structuredClone === 'function'
      ? structuredClone(valor)
      : JSON.parse(JSON.stringify(valor ?? null));
  } catch {
    return JSON.parse(JSON.stringify(valor ?? null));
  }
};
const normalizarTextoBusqueda = (valor = '') => valor.toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
const normalizarMetodoPago = (valor = '') => normalizarTextoBusqueda(valor).replace(/\s+/g, '_');
const normalizarCodigoParaComparar = (valor = '') => (valor ?? '').toString().trim().toLowerCase();
const escaparHtmlPantallaCliente = (valor = '') => (valor ?? '').toString()
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');
const tokenizarBusquedaCompuesta = (busqueda = '') => normalizarTextoBusqueda(busqueda).split(/\s+/).filter(Boolean);
const coincideBusquedaCompuesta = (campos = [], busqueda = '') => {
  const tokens = tokenizarBusquedaCompuesta(busqueda);
  if (!tokens.length) return true;
  const texto = campos
    .flatMap((campo) => Array.isArray(campo) ? campo : [campo])
    .map((campo) => normalizarTextoBusqueda(campo))
    .filter(Boolean)
    .join(' ');
  return tokens.every((token) => texto.includes(token));
};
