const crearPdfA4 = (orientacion = 'portrait', opciones = {}) => {
  const doc = new jsPDF({
    orientation: orientacion,
    unit: 'mm',
    format: 'a4',
    compress: true,
    putOnlyUsedFonts: true
  });
  if (opciones?.titulo) {
    try {
      doc.setProperties({
        title: opciones.titulo,
        subject: opciones?.asunto || opciones.titulo,
        author: opciones?.autor || 'SeniorFlow',
        creator: 'SeniorFlow'
      });
    } catch (error) {
      // jsPDF setProperties puede no estar disponible en todos los entornos.
    }
  }
  return doc;
};
const ajustarImagenA4 = (anchoImagen = 1, altoImagen = 1, orientacion = 'portrait', margenExtraMm = 0) => {
  const pageW = orientacion === 'landscape' ? PDF_A4_CONFIG.heightMm : PDF_A4_CONFIG.widthMm;
  const pageH = orientacion === 'landscape' ? PDF_A4_CONFIG.widthMm : PDF_A4_CONFIG.heightMm;
  const margen = Math.max(0, Number(margenExtraMm || 0));
  const areaW = pageW - (margen * 2);
  const areaH = pageH - (margen * 2);
  const ratio = Math.max(anchoImagen, 1) / Math.max(altoImagen, 1);
  let drawW = areaW;
  let drawH = drawW / ratio;
  if (drawH > areaH) {
    drawH = areaH;
    drawW = drawH * ratio;
  }
  const drawX = margen + ((areaW - drawW) / 2);
  const drawY = margen + ((areaH - drawH) / 2);
  return { pageW, pageH, margen, areaW, areaH, drawW, drawH, drawX, drawY };
};

const AUTO_PRINT_READY_SCRIPT = `
  <script>
    (() => {
      const waitForImages = async () => {
        const images = Array.from(document.images || []);
        await Promise.all(images.map((img) => {
          if (img.complete && img.naturalWidth > 0) return Promise.resolve();
          return new Promise((resolve) => {
            const done = () => resolve();
            img.addEventListener('load', done, { once: true });
            img.addEventListener('error', done, { once: true });
            setTimeout(done, 1000);
          });
        }));
      };
      const ready = async () => {
        try { if (document.fonts?.ready) await document.fonts.ready; } catch (error) {}
        await waitForImages();
        setTimeout(() => window.print(), 120);
      };
      if (document.readyState === 'complete') {
        ready();
      } else {
        window.addEventListener('load', ready, { once: true });
      }
    })();
  </script>
`;
const normalizarNumeroCotizacion = (valor = '') => {
  const texto = (valor ?? '').toString().trim().replace(/[^\d.,-]/g, '');
  if (!texto) return 0;
  if (texto.includes(',')) return parseFloat(texto.replace(/\./g, '').replace(',', '.')) || 0;
  return parseFloat(texto.replace(/,/g, '')) || 0;
};
const extraerCotizacionDolarBna = (html = '') => {
  const textoHtml = (html || '').toString();
  if (!textoHtml) return null;

  if (typeof DOMParser !== 'undefined') {
    const doc = new DOMParser().parseFromString(textoHtml, 'text/html');
    const filas = Array.from(doc.querySelectorAll('#billetes table.cotizacion tbody tr'));
    const filaDolar = filas.find((fila) => normalizarTextoBusqueda(fila.querySelector('.tit')?.textContent || '').includes('dolar'));
    if (filaDolar) {
      const celdas = Array.from(filaDolar.querySelectorAll('td')).map((td) => td.textContent.trim());
      const venta = normalizarNumeroCotizacion(celdas[2] || '');
      if (venta > 0) {
        const fecha = doc.querySelector('#billetes .fechaCot')?.textContent?.trim() || '';
        const hora = Array.from(doc.querySelectorAll('#billetes .legal'))
          .map((node) => node.textContent.trim())
          .find((linea) => /hora/i.test(linea)) || '';
        return { venta, compra: normalizarNumeroCotizacion(celdas[1] || ''), fecha, hora, fuente: BNA_COTIZACION_URL };
      }
    }
  }

  const match = textoHtml.match(/Dolar\s*U\.?S\.?A[\s\S]{0,180}?<td[^>]*>\s*([\d.,]+)\s*<\/td>[\s\S]{0,80}?<td[^>]*>\s*([\d.,]+)\s*<\/td>/i);
  const venta = normalizarNumeroCotizacion(match?.[2] || '');
  if (venta <= 0) return null;
  const fecha = textoHtml.match(/class=["']fechaCot["'][^>]*>\s*([^<]+)/i)?.[1]?.trim() || '';
  const hora = textoHtml.match(/Hora\s+Actualizaci[oó]n:\s*([0-9:]+)/i)?.[0]?.trim() || '';
  return { venta, compra: normalizarNumeroCotizacion(match?.[1] || ''), fecha, hora, fuente: BNA_COTIZACION_URL };
};
const extraerCotizacionDolarBlue = (html = '') => {
  const textoOriginal = (html || '').toString();
  let doc = null;
  if (typeof DOMParser !== 'undefined') {
    doc = new DOMParser().parseFromString(textoOriginal, 'text/html');
  }
  const texto = doc?.body?.textContent || textoOriginal
    .replace(/&#xF3;|&oacute;/gi, 'ó')
    .replace(/&#xED;|&iacute;/gi, 'í')
    .replace(/&#xFA;|&uacute;/gi, 'ú')
    .replace(/&nbsp;/gi, ' ')
    .replace(/<[^>]+>/g, ' ');
  if (!texto) return null;

  const extraerDesdeWidget = (docHtml = null) => {
    if (!docHtml) return null;
    const filas = Array.from(docHtml.querySelectorAll('.iframe-cotizaciones__container .data__valores p, .container__data .data__valores p'));
    if (!filas.length) return null;

    const mapa = {};
    filas.forEach((fila) => {
      const etiqueta = normalizarTextoBusqueda(fila.querySelector('span')?.textContent || '');
      const valorTexto = Array.from(fila.childNodes || [])
        .filter((nodo) => nodo.nodeType === 3)
        .map((nodo) => nodo.textContent || '')
        .join(' ')
        .trim();
      const valor = normalizarNumeroCotizacion(valorTexto);
      if (!etiqueta || valor <= 0) return;
      mapa[etiqueta] = valor;
    });

    const venta = mapa.venta || 0;
    if (venta < DOLAR_BLUE_VENTA_MIN || venta > DOLAR_BLUE_VENTA_MAX) return null;
    const compra = mapa.compra || 0;
    const actualizado = docHtml.querySelector('.fecha-container__valor')?.textContent?.trim() || '';
    return { venta, compra, fecha: actualizado, hora: actualizado, fuente: DOLAR_HOY_BLUE_WIDGET_URL };
  };

  const datosWidget = extraerDesdeWidget(doc);
  if (datosWidget) return datosWidget;

  const buscarVentaCercana = (fragmento = '') => {
    const limpio = fragmento.replace(/\s+/g, ' ');
    const matchVenta =
      limpio.match(/Venta\s*\$?\s*([\d.,]+)/i)
      || limpio.match(/([\d.,]+)\s*(?:\$)?\s*Venta/i);
    return normalizarNumeroCotizacion(matchVenta?.[1] || '');
  };

  const idxBlue = texto.search(/D[oó]lar\s*(Blue|Libre)/i);
  if (idxBlue >= 0) {
    const fragmento = texto.slice(idxBlue, idxBlue + 1200);
    const venta = buscarVentaCercana(fragmento);
    if (venta >= DOLAR_BLUE_VENTA_MIN && venta <= DOLAR_BLUE_VENTA_MAX) {
      const compraMatch =
        fragmento.match(/Compra\s*\$?\s*([\d.,]+)/i)
        || fragmento.match(/([\d.,]+)\s*(?:\$)?\s*Compra/i);
      const compra = normalizarNumeroCotizacion(compraMatch?.[1] || '');
      const actualizado = fragmento.match(/Actualizado[^:]*:\s*([^<\n]+)/i)?.[1]?.trim() || '';
      return { venta, compra, fecha: actualizado, hora: actualizado, fuente: DOLAR_BLUE_COTIZACION_URL };
    }
  }

  const tablaMatch = texto.match(/D[oó]lar\s+Libre\s*<\/?[^>]*>?\s*([\d.,]+)\s*<\/?[^>]*>?\s*([\d.,]+)/i);
  const ventaTabla = normalizarNumeroCotizacion(tablaMatch?.[2] || '');
  if (ventaTabla >= DOLAR_BLUE_VENTA_MIN && ventaTabla <= DOLAR_BLUE_VENTA_MAX) {
    return { venta: ventaTabla, compra: normalizarNumeroCotizacion(tablaMatch?.[1] || ''), fecha: '', hora: '', fuente: DOLAR_BLUE_COTIZACION_URL };
  }

  return null;
};
const extraerCotizacionDolarComercio = (html = '') => {
  const textoOriginal = (html || '').toString();
  if (!textoOriginal) return null;
  let texto = textoOriginal;
  if (typeof DOMParser !== 'undefined') {
    const doc = new DOMParser().parseFromString(textoOriginal, 'text/html');
    texto = doc?.body?.textContent || textoOriginal;
  } else {
    texto = textoOriginal
      .replace(/&#xF3;|&oacute;/gi, 'ó')
      .replace(/&#xED;|&iacute;/gi, 'í')
      .replace(/&#xFA;|&uacute;/gi, 'ú')
      .replace(/&nbsp;/gi, ' ')
      .replace(/<[^>]+>/g, ' ');
  }

  const limpio = texto.replace(/\s+/g, ' ');
  const match = limpio.match(/Precio\s+D[oó]lar\s+de\s+Facturaci[oó]n\s*:\s*\$?\s*([\d.,]+)/i);
  const venta = normalizarNumeroCotizacion(match?.[1] || '');
  if (venta < DOLAR_COMERCIO_VENTA_MIN || venta > DOLAR_COMERCIO_VENTA_MAX) return null;
  return { venta, compra: 0, fecha: '', hora: '', fuente: DOLAR_COMERCIO_COTIZACION_URL };
};
const esRecargoMoraMovimiento = (mov = null) => {
  if (!mov) return false;
  if (mov.tipo === 'recargo_mora') return true;
  return Boolean(mov?.detallesPago?.esRecargoMora);
};
const esMovimientoCargoCuentaCorriente = (mov = null) => {
  if (!mov) return false;
  if (mov.tipo === 'saldo_inicial_cc') return true;
  if (esRecargoMoraMovimiento(mov)) return normalizarMetodoPago(mov.metodoPago) === 'cuenta_corriente';
  if (mov?.detallesPago?.tipoComprobante === 'nota_credito') return false;
  return (mov.tipo === 'venta' || mov.tipo === 'ingreso_extra') && normalizarMetodoPago(mov.metodoPago) === 'cuenta_corriente';
};
const esMovimientoDescuentoCuentaCorriente = (mov = null) => {
  if (!mov) return false;
  return normalizarMetodoPago(mov.metodoPago) === 'cuenta_corriente'
    && mov?.detallesPago?.tipoComprobante === 'nota_credito';
};
const obtenerSignoPuntoVenta = (mov = null) => (
  mov?.detallesPago?.tipoComprobante === 'nota_credito' ? -1 : 1
);
