const obtenerTipoFacturaSugeridaCliente = (cliente = null) => {
  const condicion = normalizarTextoBusqueda(
    cliente?.condicionFiscal
    || cliente?.condicionIva
    || cliente?.condicion_iva
    || cliente?.situacionFiscal
    || cliente?.iva
    || ''
  );
  if (!condicion) return 'factura_b';
  if (
    condicion.includes('responsable')
    || condicion.includes('inscrip')
    || condicion.includes('ri')
    || condicion.includes('responsable inscripto')
  ) {
    return 'factura_a';
  }
  return 'factura_b';
};
