const obtenerPerfilPantalla = () => {
  if (typeof window === 'undefined') {
    return { ancho: 1024, alto: 768, tipo: 'desktop', orientacion: 'landscape', altura: 'normal', densidad: 'normal' };
  }
  const viewport = window.visualViewport || null;
  const ancho = Math.round(viewport?.width || window.innerWidth || document.documentElement?.clientWidth || 1024);
  const alto = Math.round(viewport?.height || window.innerHeight || document.documentElement?.clientHeight || 768);
  const tipo = ancho < 640 ? 'phone' : (ancho < 1024 ? 'tablet' : (ancho >= 1536 ? 'wide' : 'desktop'));
  const orientacion = ancho >= alto ? 'landscape' : 'portrait';
  const altura = alto < 620 ? 'short' : 'normal';
  const densidad = ancho < 390 || alto < 560 ? 'compact' : 'normal';
  return { ancho, alto, tipo, orientacion, altura, densidad };
};

const aplicarPerfilPantallaDocumento = (perfil) => {
  if (typeof document === 'undefined' || !perfil) return;
  const root = document.documentElement;
  root.dataset.sfScreen = perfil.tipo;
  root.dataset.sfOrientation = perfil.orientacion;
  root.dataset.sfHeight = perfil.altura;
  root.dataset.sfDensity = perfil.densidad;
  root.style.setProperty('--sf-vw', `${perfil.ancho}px`);
  root.style.setProperty('--sf-vh', `${perfil.alto}px`);
};

const usarPerfilPantalla = () => {
  const [perfil, setPerfil] = useState(() => obtenerPerfilPantalla());

  useEffect(() => {
    const actualizar = () => {
      const siguiente = obtenerPerfilPantalla();
      aplicarPerfilPantallaDocumento(siguiente);
      setPerfil((actual) => (
        actual.ancho === siguiente.ancho
        && actual.alto === siguiente.alto
        && actual.tipo === siguiente.tipo
        && actual.orientacion === siguiente.orientacion
        && actual.altura === siguiente.altura
        && actual.densidad === siguiente.densidad
          ? actual
          : siguiente
      ));
    };

    actualizar();
    window.addEventListener('resize', actualizar);
    window.addEventListener('orientationchange', actualizar);
    window.visualViewport?.addEventListener('resize', actualizar);
    window.visualViewport?.addEventListener('scroll', actualizar);

    return () => {
      window.removeEventListener('resize', actualizar);
      window.removeEventListener('orientationchange', actualizar);
      window.visualViewport?.removeEventListener('resize', actualizar);
      window.visualViewport?.removeEventListener('scroll', actualizar);
    };
  }, []);

  return perfil;
};

