class AppErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { error: null };
  }

  static getDerivedStateFromError(error) {
    return { error };
  }

  componentDidCatch(error, info) {
    console.error('Error de render en SeniorFlow', error, info);
  }

  render() {
    if (this.state.error) {
      return (
        <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4 font-sans">
          <div className="bg-white rounded-3xl shadow-xl w-full max-w-2xl overflow-hidden p-8 border border-red-100">
            <div className="flex items-start gap-4">
              <div className="bg-red-100 text-red-600 rounded-2xl p-3 shrink-0">
                <AlertCircle size={28} />
              </div>
              <div className="min-w-0">
                <h1 className="text-2xl font-black text-slate-900">Se interrumpió la carga del sistema</h1>
                <p className="mt-2 text-sm font-medium text-slate-600">
                  Evitamos la pantalla en blanco para que puedas seguir. Abajo te dejo el error capturado y un botón para recargar.
                </p>
                <div className="mt-4 bg-slate-50 border border-slate-200 rounded-2xl p-4">
                  <p className="text-[11px] font-black uppercase tracking-wider text-slate-500">Detalle técnico</p>
                  <p className="mt-2 text-sm font-mono break-words text-red-700">{this.state.error?.message || 'Error desconocido'}</p>
                </div>
                <div className="mt-5 flex flex-wrap gap-3">
                  <button
                    type="button"
                    onClick={() => window.location.reload()}
                    className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-5 rounded-xl"
                  >
                    Recargar sistema
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

