  const buscarImagenProductoEnGoogle = () => {
    const terminoDescripcion = textoSeguroTrim(formProducto?.descripcion, '');
    const terminoMarca = textoSeguroTrim(formProducto?.marca, '');
    const terminoCategoria = textoSeguroTrim(formProducto?.categoria, '');
    const consulta = [terminoDescripcion, terminoMarca, terminoCategoria].filter(Boolean).join(' ');

    if (!consulta) {
      notificarSistema('Escribí primero la descripción del producto para armar la búsqueda de imágenes.', {
        tipo: 'warning',
        titulo: 'Falta descripción'
      });
      return;
    }

    const url = `https://www.google.com/search?tbm=isch&q=${encodeURIComponent(consulta)}`;
    const ventana = window.open(url, '_blank', 'noopener,noreferrer');
    if (!ventana) {
      notificarSistema('El navegador bloqueó la apertura. Permití ventanas emergentes para buscar imágenes.', {
        tipo: 'warning',
        titulo: 'Ventana bloqueada'
      });
    }
  };

  const capturarImagenDesdePantallaProducto = async () => {
    if (!navigator.mediaDevices?.getDisplayMedia) {
      await notificarSistema('Tu navegador no permite capturar pantalla desde esta versión.', {
        tipo: 'warning',
        titulo: 'Captura no disponible'
      });
      return;
    }

    let stream = null;
    try {
      stream = await navigator.mediaDevices.getDisplayMedia({
        video: { frameRate: 12 },
        audio: false
      });
      const [track] = stream.getVideoTracks();
      const video = document.createElement('video');
      video.srcObject = stream;
      video.muted = true;
      await video.play().catch(() => {});

      await new Promise((resolve) => {
        if (video.videoWidth && video.videoHeight) {
          resolve();
          return;
        }
        video.onloadedmetadata = () => resolve();
      });

      const width = Math.max(1, video.videoWidth || 0);
      const height = Math.max(1, video.videoHeight || 0);
      if (!width || !height) throw new Error('No se pudo leer la pantalla capturada.');

      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) throw new Error('No se pudo crear el lienzo de captura.');
      ctx.drawImage(video, 0, 0, width, height);
      const dataUrl = canvas.toDataURL('image/png');
      setFormProducto((prev) => ({ ...prev, imagen: dataUrl }));
      await notificarSistema('Se capturó la pantalla y quedó cargada como imagen del producto.', {
        tipo: 'success',
        titulo: 'Captura lista'
      });
      track?.stop?.();
      stream.getTracks().forEach((t) => t.stop());
    } catch (error) {
      console.error('No se pudo capturar la pantalla del producto', error);
      await notificarSistema('No se pudo capturar la pantalla. Probá otra vez o elegí una ventana distinta.', {
        tipo: 'warning',
        titulo: 'Captura fallida'
      });
    } finally {
      if (stream) {
        stream.getTracks().forEach((t) => t.stop());
      }
    }
  };

  const pegarImagenDesdePortapapelesProducto = async () => {
    if (!navigator.clipboard?.read) {
      await notificarSistema('Tu navegador no permite leer imágenes desde el portapapeles.', {
        tipo: 'warning',
        titulo: 'Portapapeles no disponible'
      });
      return;
    }

    try {
      const items = await navigator.clipboard.read();
      for (const item of items) {
        const tipoImagen = item.types.find((type) => type.startsWith('image/'));
        if (!tipoImagen) continue;
        const blob = await item.getType(tipoImagen);
        const dataUrl = await blobADataUrl(blob);
        if (!dataUrl) continue;
        setFormProducto((prev) => ({ ...prev, imagen: dataUrl }));
        await notificarSistema('Se pegó la imagen desde el portapapeles.', {
          tipo: 'success',
          titulo: 'Imagen pegada'
        });
        return;
      }

      const texto = await navigator.clipboard.readText().catch(() => '');
      if (texto && /^https?:\/\//i.test(texto.trim())) {
        setFormProducto((prev) => ({ ...prev, imagen: texto.trim() }));
        await notificarSistema('El portapapeles tenía una URL; la dejamos lista para cargarla.', {
          tipo: 'success',
          titulo: 'URL detectada'
        });
        return;
      }

      await notificarSistema('No encontramos una imagen en el portapapeles. Copiá una imagen y volvé a intentar.', {
        tipo: 'warning',
        titulo: 'Sin imagen'
      });
    } catch (error) {
      console.error('No se pudo pegar la imagen del portapapeles', error);
      await notificarSistema('No se pudo leer el portapapeles. Probá con capturar pantalla o subir el archivo.', {
        tipo: 'warning',
        titulo: 'Portapapeles bloqueado'
      });
    }
  };

  useEffect(() => {
    if (modalActivo !== 'nuevo_producto') {
      setPuedePegarImagenProducto(false);
      return undefined;
    }

    let cancelado = false;
    const actualizarDisponibilidadPortapapeles = async () => {
      if (!navigator.clipboard?.read) {
        if (!cancelado) setPuedePegarImagenProducto(false);
        return;
      }
      try {
        const items = await navigator.clipboard.read();
        const tieneImagen = items.some((item) => (item.types || []).some((type) => type.startsWith('image/')));
        if (!cancelado) setPuedePegarImagenProducto(Boolean(tieneImagen));
      } catch {
        if (!cancelado) setPuedePegarImagenProducto(false);
      }
    };

    actualizarDisponibilidadPortapapeles();
    const intervalo = window.setInterval(actualizarDisponibilidadPortapapeles, 2000);
    return () => {
      cancelado = true;
      window.clearInterval(intervalo);
    };
  }, [modalActivo]);

