                            <p className="text-[11px] font-bold text-gray-500 mt-0.5">
                              {tipoAbonoCobro === 'ticket'
                                ? `Aplicado a ticket: ${ticketRelacionado?.descripcion || formatearFecha(ticketRelacionado?.fecha || mov.fecha)}`
                                : (tipoAbonoCobro === 'ticket_multi'
                                  ? `Aplicado a varios remitos seleccionados${Array.isArray(mov.detallesPago?.movimientoRelacionadoIds) && mov.detallesPago.movimientoRelacionadoIds.length ? ` (${mov.detallesPago.movimientoRelacionadoIds.length})` : ''}`
                                  : 'Aplicado como abono general a la deuda')}
                            </p>
